(function() {
  const bench = World.createObject('box', 'wood_bench', 0x6b4f3a, false);
  bench.scale.set(2.2, 0.35, 0.8);
  bench.position.set(2, 0.2, -4);
  if (bench.material) {
    bench.material.roughness = 0.78;
    bench.material.metalness = 0.04;
    bench.material.envMapIntensity = 0.42;
  }
})();

(function() {
  const well = World.createObject('cylinder', 'creek_well', 0x3a5a6b, false);
  well.position.set(-6, 0.5, 8);
  Object.assign(well.userData, { interactAction: 'survival', survivalKind: 'water', interactHint: 'Fill canteen', interactRadius: 2.5 });
  applySurvivalWorldHooks();
})();

(function() {
  const fan = World.createObject('cylinder', 'lab_fan', 0x888899, false);
  fan.position.set(0, 2, -3);
  if (fan.material) {
    fan.material.roughness = 0.35;
    fan.material.metalness = 0.72;
    fan.material.envMapIntensity = 0.55;
  }
  fan.userData.spin = true;
  Runtime.onTick((dt) => { fan.rotation.y += dt * 2.5; });
})();

(function() {
  const crate = World.createObject('box', 'stone_block', 0xffffff, false);
  crate.position.set(1, 0.5, 0);
  crate.userData.textures = { albedo: 'textures/stone_block_albedo.png', roughness: 'textures/stone_block_roughness.png', metalness: 'textures/stone_block_metalness.png' };
  if (window.TextureBridge) TextureBridge.apply(crate);
})();

(function() {
  const bench = World.createObject('box', 'rest_bench', 0x4a4035, false);
  bench.scale.set(1.8, 0.4, 0.7);
  bench.position.set(-2, 0.2, 5);
  Object.assign(bench.userData, { interactAction: 'survival', survivalKind: 'rest', interactHint: 'Sit and rest', interactRadius: 2 });
  applySurvivalWorldHooks();
})();

(function() {
  Engine.setRenderMode(1);
  const block = World.createObject('cube', 'retro_gallery', 0xffffff, false);
  block.position.set(0, 1, -6);
})();

(function() {
  const door = World.createObject('box', 'metal_door', 0x444455, true);
  door.scale.set(0.2, 2.2, 1.2);
  door.position.set(4, 1.1, 0);
  if (door.material) { door.material.metalness = 0.85; door.material.roughness = 0.28; }
  Object.assign(door.userData, { soundMode: 'clip', soundClipId: 'sfx_metal_clang', soundTrigger: 'collision' });
})();

(function() {
  if (!PlayerController.getLocalPlayer()) {
    PlayerController.spawnPlayer({ x: 0, y: 1, z: 8 });
  }
})();

(function() {
  if (State.env) {
    State.env.fogDensity = 0.022;
    State.env.atmosphereEnabled = true;
  }
  if (window.Engine?.applyEnv) Engine.applyEnv();
})();
